/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWFuncionarioSalario-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&PesCod.IsEmpty() AND &IncluirDemitidos.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Código") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &PesCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Status") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = '' do Case Case &IncluirDemitidos.ToString().Trim() = "S" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Incluir Demitidos"
Case &IncluirDemitidos.ToString().Trim() = "N" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = " Funcionários Vigêntes"
EndCase EndIf If not (&PesIsFun.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Funcionários") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = '' do Case Case &PesIsFun.ToString().Trim() = "true" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Somente Funcionários"
Case &PesIsFun.ToString().Trim() = "false" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Todas as Pessoas"
EndCase EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PESRAZ' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &PesRaz1.FromString(&GridStateDynamicFilter.Value) If not &PesRaz1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Funcionário", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Funcionário", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PesRaz1) EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PESRAZ' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &PesRaz2.FromString(&GridStateDynamicFilter.Value) If not &PesRaz2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Funcionário", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Funcionário", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PesRaz2) EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PESRAZ' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &PesRaz3.FromString(&GridStateDynamicFilter.Value) If not &PesRaz3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Funcionário", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome Funcionário", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&PesRaz3) EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Nome Funcionário" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Função" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Admissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Demissão"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PesRaz when &OrderedBy = 1 order PesCod when &OrderedBy = 2 AND &OrderedDsc = False order (PesCod) when &OrderedBy = 2 AND &OrderedDsc = True order PesRaz when &OrderedBy = 3 AND &OrderedDsc = False order (PesRaz) when &OrderedBy = 3 AND &OrderedDsc = True order FucCodNom when &OrderedBy = 4 AND &OrderedDsc = False order (FucCodNom) when &OrderedBy = 4 AND &OrderedDsc = True order PesSetNom when &OrderedBy = 5 AND &OrderedDsc = False order (PesSetNom) when &OrderedBy = 5 AND &OrderedDsc = True order PesIsFun when &OrderedBy = 6 AND &OrderedDsc = False order (PesIsFun) when &OrderedBy = 6 AND &OrderedDsc = True order PesDtaAdm when &OrderedBy = 7 AND &OrderedDsc = False order (PesDtaAdm) when &OrderedBy = 7 AND &OrderedDsc = True order PesDtaDem when &OrderedBy = 8 AND &OrderedDsc = False order (PesDtaDem) when &OrderedBy = 8 AND &OrderedDsc = True
using DSWWFuncionarioSalario(&PesCod, &IncluirDemitidos, &DynamicFiltersSelector1, &DynamicFiltersOperator1, &PesRaz1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &DynamicFiltersOperator2, &PesRaz2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3 , &PesRaz3, &PesIsFun)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = PesCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(PesRaz) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = WWP_Export_SecureText(FucCodNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(PesSetNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = PesIsFun.ToString() &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Date = PesDtaAdm &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Date = PesDtaDem
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWFuncionarioSalarioGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWFuncionarioSalarioGridState")) Else &GridState.FromXml(&Session.Get(!"WWFuncionarioSalarioGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"INCLUIRDEMITIDOS" &IncluirDemitidos.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESISFUN" &PesIsFun.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
